import React, { useState, useEffect } from 'react';
import { useTranslation } from '../hooks/useTranslation';

const Header = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileNavActive, setMobileNavActive] = useState(false);
  const [mobileNavClosing, setMobileNavClosing] = useState(false);
  const [activeSection, setActiveSection] = useState('');
  const [clickedItem, setClickedItem] = useState(null);
  const [isLanguageDropdownOpen, setIsLanguageDropdownOpen] = useState(false);
  const { t, toggleLanguage, currentLanguage } = useTranslation();

const navItems = [
  { href: '#sobre-mim-02', textKey: 'menu_about', id: 'sobre-mim-02' },
  { href: '#jornada', textKey: 'menu_methodologies', id: 'jornada' },
  { href: '#skills', textKey: 'menu_skills', id: 'skills' },
  { href: '#service-details', textKey: 'menu_certificates', id: 'service-details' },
  { href: '#portfolio', textKey: 'menu_projects', id: 'portfolio' },
  { href: '#form-section', textKey: 'menu_contact', id: 'form-section' },
];

  useEffect(() => {
    if (mobileNavActive) {
      document.body.classList.add('mobile-nav-active');
    } else {
      document.body.classList.remove('mobile-nav-active');
    }
    
    return () => {
      document.body.classList.remove('mobile-nav-active');
    };
  }, [mobileNavActive]);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 100);
      
      let current = '';
      const headerHeight = 100;
      const scrollPosition = window.scrollY + headerHeight;
      
      for (const item of navItems) {
        const element = document.getElementById(item.id);
        if (element) {
          const offsetTop = element.offsetTop;
          const offsetHeight = element.offsetHeight;
          
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            current = item.id;
            break;
          }
        }
      }
      
      if (!current) {
        const testimonialsElement = document.getElementById('testimonials');
        if (testimonialsElement) {
          const offsetTop = testimonialsElement.offsetTop;
          const offsetHeight = testimonialsElement.offsetHeight;
          
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            current = 'services-alt';
          }
        }
      }
      
      setActiveSection(current);
    };

    window.addEventListener('scroll', handleScroll);
    handleScroll();
    
    return () => window.removeEventListener('scroll', handleScroll);
  }, [navItems]);

  // Fechar dropdown ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (isLanguageDropdownOpen && !event.target.closest('.language-dropdown')) {
        setIsLanguageDropdownOpen(false);
      }
    };

    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [isLanguageDropdownOpen]);

  const closeMobileNav = () => {
    setMobileNavClosing(true);
    setTimeout(() => {
      setMobileNavActive(false);
      setMobileNavClosing(false);
    }, 300);
  };

  const handleNavClick = (sectionId) => {
    setClickedItem(sectionId);
    setTimeout(() => setClickedItem(null), 300);
    
    if (mobileNavActive) {
      closeMobileNav();
    }
    
    setActiveSection(sectionId);
  };

  const toggleMobileNav = () => {
    if (mobileNavActive) {
      closeMobileNav();
    } else {
      setMobileNavActive(true);
    }
  };

  const scrollToSection = (id) => {
    const element = document.getElementById(id);
    if (element) {
      const header = document.querySelector('#header');
      const headerHeight = header ? header.offsetHeight : 100;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerHeight;
      
      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  const openCV = () => {
    const cvPath = '/assets/CV/matheus_abib_curriculo.pdf';
    window.open(cvPath, '_blank');
  };

  const changeLanguage = (lang) => {
    if (currentLanguage !== lang) {
      toggleLanguage();
    }
    setIsLanguageDropdownOpen(false);
  };

  return (
    <>
      <header 
        id="header" 
        className={`header d-flex align-items-center fixed-top ${scrolled ? 'scrolled' : ''}`}
      >      
        <div className="container position-relative d-flex align-items-center justify-content-between">
          <div 
            className="logo d-flex align-items-center" 
            onClick={() => {
              handleNavClick('hero');
              scrollToSection('hero');
            }}
            style={{cursor: 'pointer'}}
          >
            <h1 className="sitename">Matheus Abib</h1><span>.</span>
          </div>

          <nav id="navmenu" className={`navmenu ${mobileNavActive ? 'mobile-nav-active' : ''} ${mobileNavClosing ? 'mobile-nav-closing' : ''}`}>
            <ul>
              {navItems.map((item) => (
                <li key={item.id}>
                  <a 
                    href={item.href}
                    onClick={(e) => {
                      e.preventDefault();
                      handleNavClick(item.id);
                      scrollToSection(item.id);
                    }}
                    className={`d-flex align-items-center ${activeSection === item.id ? 'active' : ''} ${clickedItem === item.id ? 'clicked' : ''}`}
                  >
                    {activeSection === item.id && (
                      <span className="active-dot me-2"></span>
                    )}
                    <span data-translate={item.textKey}>{t(item.textKey)}</span>
                  </a>
                </li>
              ))}
              <li className="d-block d-xl-none mt-3 pt-3 border-top">
                <div className="language-dropdown-mobile">
                  <button 
                    className="btn-language-mobile w-100 d-flex justify-content-between align-items-center"
                    onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}
                  >
                    <div className="d-flex align-items-center gap-2">
                      <i className="bi bi-translate"></i>
                      <span>{currentLanguage === 'pt' ? 'Português' : 'English'}</span>
                    </div>
                    <i className={`bi bi-chevron-${isLanguageDropdownOpen ? 'up' : 'down'}`}></i>
                  </button>
                  {isLanguageDropdownOpen && (
                    <ul className="dropdown-menu-mobile show">
                      <li>
                        <button 
                          className={`dropdown-item-mobile ${currentLanguage === 'pt' ? 'active' : ''}`}
                          onClick={() => changeLanguage('pt')}
                        >
                          <i className="bi bi-flag-br"></i>
                          <span>Português</span>
                        </button>
                      </li>
                      <li>
                        <button 
                          className={`dropdown-item-mobile ${currentLanguage === 'en' ? 'active' : ''}`}
                          onClick={() => changeLanguage('en')}
                        >
                          <i className="bi bi-flag-us"></i>
                          <span>English</span>
                        </button>
                      </li>
                    </ul>
                  )}
                </div>
              </li>
            </ul>
            <i 
              className="mobile-nav-close bi bi-x d-xl-none"
              onClick={closeMobileNav}
              aria-label="Close navigation"
            ></i>
          </nav>

          <div className="d-none d-xl-flex align-items-center gap-2">
            {/* Botão de CV com dropdown */}
            <div className="cv-button-wrapper">
              <button 
                className="btn-cv"
                onClick={openCV}
              >
                <i className="bi bi-file-text me-1"></i>
                <span data-translate="btn_cv">CV</span>
                <i className="bi bi-chevron-down ms-1"></i>
              </button>
            </div>

            {/* Dropdown de Idioma Desktop */}
            <div className="language-dropdown">
              <button 
                className="btn-language"
                onClick={() => setIsLanguageDropdownOpen(!isLanguageDropdownOpen)}
              >
                <i className="bi bi-translate"></i>
                <span>{currentLanguage === 'pt' ? 'PT' : 'EN'}</span>
                <i className={`bi bi-chevron-${isLanguageDropdownOpen ? 'up' : 'down'}`}></i>
              </button>
              {isLanguageDropdownOpen && (
                <ul className="dropdown-menu-language show">
                  <li>
                    <button 
                      className={`dropdown-item-language ${currentLanguage === 'pt' ? 'active' : ''}`}
                      onClick={() => changeLanguage('pt')}
                    >
                      <i className="bi bi-flag-br"></i>
                      <span>Português</span>
                    </button>
                  </li>
                  <li>
                    <button 
                      className={`dropdown-item-language ${currentLanguage === 'en' ? 'active' : ''}`}
                      onClick={() => changeLanguage('en')}
                    >
                      <i className="bi bi-flag-us"></i>
                      <span>English</span>
                    </button>
                  </li>
                </ul>
              )}
            </div>
          </div>

          <i 
            className={`mobile-nav-toggle d-xl-none bi ${mobileNavActive ? 'bi-x' : 'bi-list'}`}
            onClick={toggleMobileNav}
            aria-label="Toggle navigation"
          ></i>
        </div>
      </header>

      {mobileNavActive && (
        <div 
          className="mobile-nav-overlay"
          onClick={closeMobileNav}
        ></div>
      )}
    </>
  );
};

export default Header;
